"""Deterministic offline embeddings — spirit v1, no model download."""

from __future__ import annotations

import hashlib
import math
import struct


DIM = 64


def embed_text(text: str, dim: int = DIM) -> list[float]:
    """Hash n-grams into a unit vector. Review demo, not semantic truth."""
    vec = [0.0] * dim
    normalized = text.lower().strip()
    if not normalized:
        return vec

    for i in range(len(normalized) - 2):
        gram = normalized[i : i + 3]
        digest = hashlib.sha256(gram.encode()).digest()
        idx = int.from_bytes(digest[:4], "big") % dim
        sign = 1.0 if digest[4] % 2 == 0 else -1.0
        vec[idx] += sign

    for token in normalized.split():
        digest = hashlib.sha256(token.encode()).digest()
        idx = int.from_bytes(digest[:4], "big") % dim
        vec[idx] += 1.0

    norm = math.sqrt(sum(v * v for v in vec))
    if norm == 0:
        return vec
    return [v / norm for v in vec]


def embedding_to_blob(vec: list[float]) -> bytes:
    return struct.pack(f"{len(vec)}f", *vec)


def blob_to_embedding(blob: bytes) -> list[float]:
    n = len(blob) // 4
    return list(struct.unpack(f"{n}f", blob))


def cosine(a: list[float], b: list[float]) -> float:
    if len(a) != len(b) or not a:
        return 0.0
    return sum(x * y for x, y in zip(a, b))

"""Exhale warnings — productive friction on the stream."""

from __future__ import annotations

HEDGED_MARKERS = (
    "didn't we",
    "didnt we",
    "probably",
    "i feel",
    "might ",
    "maybe ",
    "somewhere in there",
)


def build_exhale_warnings(pool_hits: list[dict], ground: list[dict]) -> list[dict]:
    warnings: list[dict] = []
    seen: set[str] = set()

    def add(text: str) -> None:
        if text not in seen:
            seen.add(text)
            warnings.append({"text": text, "authority": "warning"})

    if not pool_hits:
        return warnings

    top = pool_hits[0]
    sim = float(top.get("similarity") or 0)
    if not top.get("source_ref") and sim >= 0.15:
        add(
            "Top pool hit lacks source_ref — similarity must not become Settle"
        )

    for hit in pool_hits[:3]:
        lower = (hit.get("text") or "").lower()
        if any(marker in lower for marker in HEDGED_MARKERS):
            add("Pool hit contains hedged language — keep as pressure, not ground")
            break

    if ground and pool_hits:
        add(
            "Ground and pressure both present — settled facts must not lend certainty to unsettled spray"
        )

    if pool_hits and not ground and sim >= 0.35:
        add("Strong pool nearness but no settled depth for this query")

    return warnings

